-- PROCEDURE P_COST_BOM_INSERT

  CREATE OR REPLACE EDITIONABLE PROCEDURE "CMX"."P_COST_BOM_INSERT" (
    p_docid IN t_cost_pinggu.docid%TYPE  -- 输入参数：指定主表DOCID
) AS
    v_goodsid varchar2(20);
    v_raw_goodsid t_cost_pinggu.goodsid%TYPE; -- 添加变量存储原始goodsid
    v_xx number;
BEGIN


    -- 1. 检查主表是否存在指定docid
    SELECT goodsid INTO v_raw_goodsid
    FROM t_cost_pinggu
    WHERE docid = p_docid
    ;
     -- 新增BOM存在性检查
    IF v_raw_goodsid IS NULL THEN
        RAISE_APPLICATION_ERROR(-20003, '该产品在ERP中不存在BOM');
    END IF;

    v_goodsid := '-' || v_raw_goodsid||'-';  -- 拼接前缀

    --增加一步删除操作
    delete from t_cost_pinggu_dtl where docid=p_docid;

    -- 2. 插入关联的子表数据
    INSERT INTO t_cost_pinggu_dtl (
        dtlid,      -- 子表主键（序列自增）
        docid,      -- 关联主表的外键
        goodsid,    -- 视图字段
        STANDARDTYPE,           --质量规格
        batch_qty,
        price,
        BASE_PRICE,
        modifydate,
        cost_batch,
        --apex_goodsname,  -- 视图字段
        DTL_USEFLAG,     -- 视图字段
        GOODSNAME,
        FACTORYNAME,
        GOODSTYPE
    )
    SELECT
        SEQ_COST_PINGGU_DTL.NEXTVAL,  -- 生成子表主键
        p_docid,                      -- 使用输入参数docid
        v.goodsid,                    -- 视图中的goodsid
        v.standardtype,               --
        v.useqty,                      --数量
        f.PRICE,
        f.PRICE,
        sysdate,
        nvl(v.useqty,0)*nvl(f.price,0),
        --v.goodsname,                  -- 视图中的goodsname
       decode(v.useflag,4,'原料',2,'辅料',3,'非印字包材',5,'印字包材'),
        f.GOODSNAME,
        f.FACTORYNAME,
        f.GOODSTYPE
    FROM t_cost_bom_goods_tree_v v,PUB_GOODS_V f
    WHERE v.treeid like v_goodsid||'%' and v.pid<>'-1' and v.USEFLAG not in (0,1)
    and v.goodsid=f.goodsid(+);       -- 按主表goodsid匹配视图

    p_pinggu_dtl_compute(p_docid);
    p_pinggu_compute(p_docid);

    COMMIT;

END P_COST_BOM_INSERT;
/
/

-- PROCEDURE P_COST_BOM_INSERT_LQ

  CREATE OR REPLACE EDITIONABLE PROCEDURE "CMX"."P_COST_BOM_INSERT_LQ" (p_docid IN t_cost_pinggu_lq.docid%TYPE) AS
    v_goodsid varchar2(20);
    v_raw_goodsid t_cost_pinggu_lq.goodsid%TYPE;
BEGIN
    SELECT goodsid INTO v_raw_goodsid FROM t_cost_pinggu_lq WHERE docid = p_docid;
    IF v_raw_goodsid IS NULL THEN RAISE_APPLICATION_ERROR(-20003, '该产品在ERP中不存在BOM'); END IF;
    v_goodsid := '-' || v_raw_goodsid || '-';
    DELETE FROM t_cost_pinggu_dtl_lq WHERE docid = p_docid;
    INSERT INTO t_cost_pinggu_dtl_lq (dtlid, docid, goodsid,standardtype, batch_qty, price, BASE_PRICE, modifydate, cost_batch,
                                   DTL_USEFLAG, GOODSNAME, FACTORYNAME, GOODSTYPE)
    SELECT SEQ_COST_PINGGU_DTL_LQ.NEXTVAL, p_docid, v.goodsid, v.standardtype, v.useqty, f.PRICE, f.PRICE, sysdate,
           nvl(v.useqty,0)*nvl(f.price,0), decode(v.useflag,4,'原料',2,'辅料',3,'非印字包材',5,'印字包材'),
           f.GOODSNAME, f.FACTORYNAME, f.GOODSTYPE
    FROM t_cost_bom_goods_tree_v v, PUB_GOODS_V f
    WHERE v.treeid LIKE v_goodsid||'%' AND v.pid <> '-1' AND v.USEFLAG NOT IN (0,1) AND v.goodsid = f.goodsid(+);
    p_pinggu_dtl_compute_lq(p_docid);
    p_pinggu_compute_lq(p_docid);
    COMMIT;
END P_COST_BOM_INSERT_LQ;
/
/

-- PROCEDURE P_DEMAND_APPROVAL_SET_RECEIVER

  CREATE OR REPLACE EDITIONABLE PROCEDURE "CMX"."P_DEMAND_APPROVAL_SET_RECEIVER" (
  P_BILL_ID     IN NUMBER,
  P_PARAMS_JSON IN CLOB
) AS
  V_RECEIVER VARCHAR2(200);
BEGIN
  IF P_BILL_ID IS NULL THEN
    RAISE_APPLICATION_ERROR(-20001, '页面主表ID不能为空');
  END IF;

  IF P_PARAMS_JSON IS NOT NULL THEN
    SELECT COALESCE(
             JSON_VALUE(P_PARAMS_JSON, '$.receiverName' RETURNING VARCHAR2(200) NULL ON ERROR),
             JSON_VALUE(P_PARAMS_JSON, '$.name' RETURNING VARCHAR2(200) NULL ON ERROR),
             JSON_VALUE(P_PARAMS_JSON, '$.businessReceiver' RETURNING VARCHAR2(200) NULL ON ERROR),
             JSON_VALUE(P_PARAMS_JSON, '$.handlerName' RETURNING VARCHAR2(200) NULL ON ERROR)
           )
      INTO V_RECEIVER
      FROM DUAL;
  END IF;

  V_RECEIVER := TRIM(V_RECEIVER);
  IF V_RECEIVER IS NULL THEN
    RAISE_APPLICATION_ERROR(-20002, '业务接收处理人不能为空，请在页面参数中传 receiverName 或 name');
  END IF;

  UPDATE T_DEMAND_APPLICATION
     SET BUSINESS_RECEIVER = V_RECEIVER,
         UPDATE_TIME = SYSDATE,
         UPDATE_BY = 'approval-procedure'
   WHERE ID = P_BILL_ID
     AND NVL(DELETED, 0) = 0;

  IF SQL%ROWCOUNT = 0 THEN
    RAISE_APPLICATION_ERROR(-20003, '未找到项目审批表单据，ID=' || P_BILL_ID);
  END IF;
END P_DEMAND_APPROVAL_SET_RECEIVER;
/
/

-- PROCEDURE P_PINGGU_COMPUTE

  CREATE OR REPLACE EDITIONABLE PROCEDURE "CMX"."P_PINGGU_COMPUTE" (p_docid IN NUMBER) IS
  v_apex_pl       NUMBER;
  v_p_perpack     NUMBER;
  v_yield         NUMBER;
  v_out_price_rmb NUMBER;
  v_annual_qty    NUMBER;
  v_total_fl      NUMBER;
  v_total_bc      NUMBER;
  v_total_yl      NUMBER;
  v_total_cost    NUMBER;
  v_salemoney     NUMBER;
  v_jgf_batch     NUMBER;
  v_jgf_perqp     NUMBER;
  v_cost_perqp    NUMBER;
  v_ml_perqp      NUMBER;
  v_y_jg_re       NUMBER;
  v_y_ml          NUMBER;
  v_y_sale        NUMBER;
  v_cost_perbox   NUMBER;
  is_exists        NUMBER;
BEGIN
  SELECT COUNT(1)
    INTO is_exists
    FROM t_cost_pinggu_lq
   WHERE docid = p_docid;
  IF is_exists > 0 THEN
    SELECT apex_pl, yield, out_price_rmb, annual_qty, cost_perqp
      INTO v_apex_pl,
           v_yield,
           v_out_price_rmb,
           v_annual_qty,
           v_cost_perqp
      FROM t_cost_pinggu_lq
     WHERE docid = p_docid;
  
    SELECT NVL(SUM(CASE
                     WHEN dtl_useflag = '原料' THEN
                      cost_batch
                     ELSE
                      0
                   END),
               0),
           NVL(SUM(CASE
                     WHEN dtl_useflag = '辅料' THEN
                      cost_batch
                     ELSE
                      0
                   END),
               0),
           NVL(SUM(CASE
                     WHEN dtl_useflag IN ('非印字包材', '印字包材') THEN
                      cost_batch
                     ELSE
                      0
                   END),
               0)
      INTO v_total_yl, v_total_fl, v_total_bc
      FROM t_cost_pinggu_dtl_lq
     WHERE docid = p_docid;

    IF v_total_yl > 0 THEN
      v_total_yl := v_total_yl / 1.13;
      v_total_fl := v_total_fl / 1.13;
      v_total_bc := v_total_bc / 1.13;
    END IF;

  v_total_cost  := v_total_fl + v_total_bc + v_total_yl;
  v_salemoney   := ROUND(NVL(v_out_price_rmb, 0) / NULLIF(v_p_perpack, 0) *
                         NVL(v_apex_pl, 0) * (NVL(v_yield, 0) / 100),
                         2);
  v_jgf_batch   := ROUND(NVL(v_salemoney, 0) - NVL(v_total_cost, 0), 2);
  v_cost_perbox := ROUND(NVL(v_total_cost, 0) / NULLIF(v_apex_pl, 0) *
                         NVL(v_p_perpack, 0),
                         2);
  v_jgf_perqp   := ROUND(NVL(v_jgf_batch, 0) / NULLIF(v_apex_pl, 0) * 1000,
                         2);
  v_ml_perqp    := ROUND(NVL(v_jgf_perqp, 0) - NVL(v_cost_perqp, 0), 2);
  v_y_jg_re     := ROUND(NVL(v_jgf_perqp, 0) / 1000 * NVL(v_annual_qty, 0),
                         2);
  v_y_ml        := ROUND(NVL(v_ml_perqp, 0) / 1000 * NVL(v_annual_qty, 0),
                         2);
  v_y_sale      := ROUND(NVL(v_annual_qty, 0) / NULLIF(v_p_perpack, 0) *
                         NVL(v_out_price_rmb, 0) * NVL(v_yield, 0),
                         2);

  UPDATE t_cost_pinggu
     SET salemoney   = v_salemoney,
         jgf_batch   = v_jgf_batch,
         jgf_perqp   = v_jgf_perqp,
         cost_perbox = v_cost_perbox,
         ml_perqp    = v_ml_perqp,
         y_jg_re     = v_y_jg_re,
         y_ml        = v_y_ml,
         y_sale      = v_y_sale,
         total_fl    = v_total_fl,
         total_bc    = v_total_bc,
         total_yl    = v_total_yl,
         total_cost  = v_total_cost
   WHERE docid = p_docid;
     END IF;
EXCEPTION
  WHEN NO_DATA_FOUND THEN
    ROLLBACK;
    RAISE;
  WHEN OTHERS THEN
    ROLLBACK;
    RAISE;
END p_pinggu_compute;
/
/

-- PROCEDURE P_PINGGU_COMPUTE_ALL

  CREATE OR REPLACE EDITIONABLE PROCEDURE "CMX"."P_PINGGU_COMPUTE_ALL" /*(p_docid number)*/ as
begin
  UPDATE t_cost_pinggu_dtl a
     SET a.price =
         (SELECT PRICE
            FROM t_cost_goods x
           WHERE x.GOODSID = a.goodsid
             and x.USEFLAG NOT IN ('产成品','半成品'));

  FOR i IN (SELECT DOCID FROM t_cost_pinggu) LOOP
    p_pinggu_dtl_compute(i.docid);
    p_pinggu_compute(i.docid);
  END LOOP;
end;
