-- PROCEDURE P_PINGGU_COMPUTE_LQ

  CREATE OR REPLACE EDITIONABLE PROCEDURE "CMX"."P_PINGGU_COMPUTE_LQ" (p_docid IN NUMBER) IS
  v_apex_pl       NUMBER;
  v_yield         NUMBER;
  v_out_price_rmb NUMBER;
  v_annual_qty    NUMBER;
  v_total_fl      NUMBER;
  v_total_bc      NUMBER;
  v_total_yl      NUMBER;
  v_total_cost    NUMBER;
  v_salemoney     NUMBER;
  v_jgf_batch     NUMBER;
  v_jgf_perqp     NUMBER;
  v_cost_perqp    NUMBER;
  v_ml_perqp      NUMBER;
  v_y_jg_re       NUMBER;
  v_y_ml          NUMBER;
  v_y_sale        NUMBER;
  v_cost_perbox   NUMBER;
  is_exists       NUMBER;
BEGIN
  SELECT COUNT(1)
    INTO is_exists
    FROM t_cost_pinggu_lq
   WHERE docid = p_docid;
  IF is_exists > 0 THEN
    SELECT apex_pl, yield, out_price_rmb, annual_qty, cost_perqp
      INTO v_apex_pl,
           v_yield,
           v_out_price_rmb,
           v_annual_qty,
           v_cost_perqp
      FROM t_cost_pinggu_lq
     WHERE docid = p_docid;
  
    SELECT NVL(SUM(CASE
                     WHEN dtl_useflag = '原料' THEN
                      cost_batch
                     ELSE
                      0
                   END),
               0),
           NVL(SUM(CASE
                     WHEN dtl_useflag = '辅料' THEN
                      cost_batch
                     ELSE
                      0
                   END),
               0),
           NVL(SUM(CASE
                     WHEN dtl_useflag IN ('非印字包材', '印字包材') THEN
                      cost_batch
                     ELSE
                      0
                   END),
               0)
      INTO v_total_yl, v_total_fl, v_total_bc
      FROM t_cost_pinggu_dtl_lq
     WHERE docid = p_docid;

    IF v_total_yl > 0 THEN
      v_total_yl := v_total_yl / 1.13;
      v_total_fl := v_total_fl / 1.13;
      v_total_bc := v_total_bc / 1.13;
    END IF;
  
    v_total_cost  := v_total_fl + v_total_bc + v_total_yl;
    v_salemoney   := NVL(v_out_price_rmb, 0) * NULLIF(v_apex_pl, 0) *
                     (NVL(v_yield, 0) / 100);
    v_jgf_batch   := NVL(v_salemoney, 0) - NVL(v_total_cost, 0);
    v_cost_perbox := NVL(v_total_cost, 0) / NULLIF(v_apex_pl, 0);
    v_jgf_perqp   := NVL(v_jgf_batch, 0) / NULLIF(v_apex_pl, 0) ;
    v_ml_perqp    := NVL(v_jgf_perqp, 0) - NVL(v_cost_perqp, 0);
    v_y_jg_re     := NVL(v_jgf_perqp, 0) * NULLIF(v_annual_qty, 0);
    v_y_ml        := NVL(v_ml_perqp, 0) * NULLIF(v_annual_qty, 0);
    v_y_sale      := NVL(v_annual_qty, 0) * NVL(v_out_price_rmb, 0) *
                     NVL(v_yield, 0);
  
    UPDATE t_cost_pinggu_lq
       SET salemoney   = v_salemoney,
           jgf_batch   = v_jgf_batch,
           jgf_perqp   = v_jgf_perqp,
           cost_perbox = v_cost_perbox,
           ml_perqp    = v_ml_perqp,
           y_jg_re     = v_y_jg_re,
           y_ml        = v_y_ml,
           y_sale      = v_y_sale,
           total_fl    = v_total_fl,
           total_bc    = v_total_bc,
           total_yl    = v_total_yl,
           total_cost  = v_total_cost
     WHERE docid = p_docid;
  END IF;
EXCEPTION
  WHEN NO_DATA_FOUND THEN
    ROLLBACK;
    RAISE;
  WHEN OTHERS THEN
    ROLLBACK;
    RAISE;
END p_pinggu_compute_lq;
/
/

-- PROCEDURE P_PINGGU_DTL_COMPUTE

  CREATE OR REPLACE EDITIONABLE PROCEDURE "CMX"."P_PINGGU_DTL_COMPUTE" (p_docid number) as
  v_apex_pl number;
begin
  begin
    select a.apex_pl
      into v_apex_pl
      from t_cost_pinggu_lq a
     where a.docid = p_docid;
  exception
    when no_data_found then
      return;
  end;

  update t_cost_pinggu_dtl_lq a
     set a.per_hl = a.batch_qty / v_apex_pl * 1000000
   where a.docid = p_docid
     and a.dtl_useflag in ('原料', '辅料');

  merge into t_cost_pinggu_dtl a
  using (
    select b.dtlid,
           case
             when b.dtl_useflag in ('非印字包材', '印字包材')
               and regexp_like(b.goodsname, '桶|说明书|小盒|标签|瓶|盖')
             then round((b.apex_pl / nullif(b.p_perpack, 0)) *
                        (1 + nvl(b.exadd_mater, 0) / 100), 4)

             when b.dtl_useflag = '辅料'
               and regexp_like(b.goodsname, '胶囊')
             then round((b.apex_pl / 10000) *
                        (1 + nvl(b.exadd_mater, 0) / 100), 4)

             when b.dtl_useflag in ('原料', '辅料')
             then round((b.per_hl * b.apex_pl *
                        (1 + nvl(b.exadd_mater, 0) / 100) / 1000000), 4)

             when b.dtl_useflag in ('印字包材', '非印字包材')
               and regexp_like(b.goodsname, '硬片|铝箔|复合膜')
             then round((b.per_hl * b.apex_pl *
                        (1 + nvl(b.exadd_mater, 0) / 100) / 1000000), 4)

             when b.dtl_useflag in ('非印字包材', '印字包材')
               and regexp_like(b.goodsname, '大纸箱')
             then round(ceil(b.apex_pl / (b.p_perpack * b.s_perback) *
                        (1 + nvl(b.exadd_mater, 0) / 100)), 4)

             when b.dtl_useflag in ('非印字包材', '印字包材')
               and regexp_like(b.goodsname, '托盘')
             then round(ceil(b.apex_pl / (b.p_perpack * b.s_perback * b.x_perback) *
                        (1 + nvl(b.exadd_mater, 0) / 100)), 4)

             when b.dtl_useflag in ('非印字包材', '印字包材')
               and regexp_like(b.goodsname, '中盒')
             then round(ceil(b.apex_pl / (b.m_perpack * b.s_perback) *
                        (1 + nvl(b.exadd_mater, 0) / 100)), 4)

             else b.batch_qty
           end as new_batch_qty
      from t_cost_pinggu_dtl_v b
     where b.docid = p_docid
  ) x
  on (a.dtlid = x.dtlid)
  when matched then
    update
       set a.batch_qty = x.new_batch_qty,
           a.cost_batch = x.new_batch_qty * a.price
     where a.docid = p_docid;
end p_pinggu_dtl_compute;
/
/

-- PROCEDURE P_PINGGU_DTL_COMPUTE_LQ

  CREATE OR REPLACE EDITIONABLE PROCEDURE "CMX"."P_PINGGU_DTL_COMPUTE_LQ" (p_docid number) as
  v_apex_pl number;
begin
  begin
    select a.apex_pl
      into v_apex_pl
      from t_cost_pinggu_lq a
     where a.docid = p_docid;
  exception
    when no_data_found then
      return;
  end;

  -- is_all_comp 不再参与判断，直接更新
  update t_cost_pinggu_dtl_lq a
     set a.per_hl = a.batch_qty / v_apex_pl * 1000000
   where a.docid = p_docid
     and a.dtl_useflag in ('原料', '辅料');

  merge into t_cost_pinggu_dtl_lq a
  using (
    select b.dtlid,
           case
             -- CostMaterialLq.batchQty = perHl * (1 + exaddMater/100) / 1000000
             when b.dtl_useflag in ('原料', '辅料')
             then round(b.per_hl * (1 + nvl(b.exadd_mater, 0) / 100) / 1000000, 4)

             -- CostPackageLq.batchQty 分支 0
             when b.dtl_useflag in ('印字包材', '非印字包材')
               and regexp_like(b.goodsname, '桶|说明书|小盒|标签|瓶|盖注射器|适配器|量杯|勺|分度器')
             then round((b.apex_pl / nullif(b.p_perpack, 0)) *
                        (1 + nvl(b.exadd_mater, 0) / 100), 4)

             -- CostPackageLq.batchQty 分支 1：大纸箱
             when b.dtl_useflag in ('印字包材', '非印字包材')
               and regexp_like(b.goodsname, '大纸箱')
             then round(ceil((b.apex_pl / nullif(b.p_perpack * b.s_perback, 0)) *
                        (1 + nvl(b.exadd_mater, 0) / 100)), 4)

             -- CostPackageLq.batchQty 分支 2：托盘
             when b.dtl_useflag in ('印字包材', '非印字包材')
               and regexp_like(b.goodsname, '托盘')
             then round(ceil((b.apex_pl / nullif(b.p_perpack * b.s_perback * b.x_perback, 0)) *
                        (1 + nvl(b.exadd_mater, 0) / 100)), 4)

             else b.batch_qty
           end as new_batch_qty
      from t_cost_pinggu_dtl_lq_v b
     where b.docid = p_docid
  ) x
     on (a.dtlid = x.dtlid)
  when matched then
    update
       set a.batch_qty  = x.new_batch_qty,
           -- CostMaterialLq / CostPackageLq.costBatch = batchQty * price
           a.cost_batch = x.new_batch_qty * a.price
     where a.docid = p_docid;

end;
/
/

-- PROCEDURE P_RESET_PASSWORD

  CREATE OR REPLACE EDITIONABLE PROCEDURE "CMX"."P_RESET_PASSWORD" (
    p_ids       IN VARCHAR2,    -- 逗号分隔的用户ID列表，如 '1,2,3'
    p_user_id   IN NUMBER,      -- 当前操作用户ID
    p_result    OUT NUMBER,     -- 返回码：0=成功，其他=失败
    p_message   OUT VARCHAR2    -- 返回消息
) AS
    v_count NUMBER := 0;
    v_operator VARCHAR2(50);
    -- BCrypt 加密后的 abc123.. 密文（使用 Spring Security BCryptPasswordEncoder 生成）
    -- 注意：此哈希值与 DynamicDataService 中的默认密码(admin)使用相同格式
    v_new_password VARCHAR2(100) := '$2a$10$igs26ZAhFQFArWFszhIrn.MSMheCLYW9ertSP5J53jrgjKRpFhdE.';
BEGIN
    -- 获取操作人用户名
    BEGIN
        SELECT USERNAME INTO v_operator FROM T_COST_USER WHERE ID = p_user_id;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            v_operator := 'system';
    END;

    -- 更新密码（支持多个ID）
    UPDATE T_COST_USER
    SET PASSWORD = v_new_password,
        UPDATE_TIME = SYSDATE,
        UPDATE_BY = v_operator
    WHERE ID IN (
        SELECT TO_NUMBER(TRIM(REGEXP_SUBSTR(p_ids, '[^,]+', 1, LEVEL)))
        FROM DUAL
        CONNECT BY LEVEL <= REGEXP_COUNT(p_ids, ',') + 1
    );

    v_count := SQL%ROWCOUNT;

    IF v_count > 0 THEN
        p_result := 0;
        p_message := '已重置 ' || v_count || ' 个用户的密码为 admin';
        COMMIT;
    ELSE
        p_result := 1;
        p_message := '未找到要重置的用户';
    END IF;

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        p_result := 1;
        p_message := '重置密码失败: ' || SQLERRM;
END P_RESET_PASSWORD;
/
/

-- PROCEDURE P_WMS_SYNC_BY_CONID

  CREATE OR REPLACE EDITIONABLE PROCEDURE "CMX"."P_WMS_SYNC_BY_CONID" (
  p_conid IN NUMBER
) AS
BEGIN
  -- 删除该 CONID 下的旧数据
  DELETE FROM T_WMS_QTY WHERE CONID = p_conid;
  DELETE FROM T_WMS_QTY_DETAIL WHERE CONID = p_conid;

  -- 插入库存汇总数据
  INSERT INTO T_WMS_QTY (ID, CONID, GOODSID, GOODSGP, LOTNO, GOODSNO, PACKSIZE, QTY_SHOW, PCS, TRANPOSNAME, DELETED, CREATE_TIME, CREATE_BY)
  SELECT SEQ_WMS_QTY.NEXTVAL,
         t.conid,
         t.goodsid,
         t.goodsgp,
         t.lotno,
         t.goodsno,
         t.packsize,
         t.qty_show,
         t.pcs,
         t.tranposname,
         0,
         SYSTIMESTAMP,
         'system'
    FROM T_WMS_QTY_V t
   WHERE t.conid = p_conid;

  -- 插入库存明细数据
  INSERT INTO T_WMS_QTY_DETAIL (ID, RN, CONID, GOODSID, GOODSNAME, LOTNO, PCS, VALIDDATE, DELETED, CREATE_TIME, CREATE_BY,Goodsqty,containerno)
  SELECT SEQ_WMS_QTY_DETAIL.NEXTVAL,
         t.rn,
         t.conid,
         t.goodsid,
         t.goodsname,
         t.lotno,
         t.pcs,
         t.validdate,
         0,
         SYSTIMESTAMP,
         'system',
         Goodsqty,
         t.containerno
    FROM T_WMS_QTY_DETAIL_V t
   WHERE t.conid = p_conid;

  COMMIT;
END;
/
/

